INSERT INTO texts (title, hanzi, pinyin, translation, hsk_level) VALUES
(
    'Один день на рынке',
    '我家附近有一个很大的市场,那里的东西很多,也不贵。星期六早上,妈妈常常带我一起去市场买菜。市场里有卖水果的,有卖蔬菜的,还有卖鱼和肉的。我最喜欢跟着妈妈去买水果,因为水果又甜又好吃。今天我们买了苹果、香蕉和西瓜。妈妈还买了鸡蛋、牛奶和面包。市场里的人很多,也很热闹,大家都在说话、买东西。买完东西以后,我们坐公共汽车回家。到家的时候,我已经很饿了,妈妈马上给我们做饭。我们一家人一起吃饭,聊今天在市场看到的有意思的事情。我很喜欢星期六,因为可以和妈妈一起去市场。',
    'Wǒ jiā fùjìn yǒu yí gè hěn dà de shìchǎng, nàlǐ de dōngxi hěn duō, yě bú guì. Xīngqīliù zǎoshang, māma chángcháng dài wǒ yìqǐ qù shìchǎng mǎi cài. Shìchǎng lǐ yǒu mài shuǐguǒ de, yǒu mài shūcài de, hái yǒu mài yú hé ròu de. Wǒ zuì xǐhuan gēnzhe māma qù mǎi shuǐguǒ, yīnwèi shuǐguǒ yòu tián yòu hǎochī. Jīntiān wǒmen mǎile píngguǒ, xiāngjiāo hé xīguā. Māma hái mǎile jīdàn, niúnǎi hé miànbāo. Shìchǎng lǐ de rén hěn duō, yě hěn rènao, dàjiā dōu zài shuōhuà, mǎi dōngxi. Mǎiwán dōngxi yǐhòu, wǒmen zuò gōnggòng qìchē huí jiā. Dào jiā de shíhou, wǒ yǐjīng hěn è le, māma mǎshàng gěi wǒmen zuòfàn. Wǒmen yìjiā rén yìqǐ chīfàn, liáo jīntiān zài shìchǎng kàndào de yǒuyìsi de shìqing. Wǒ hěn xǐhuan xīngqīliù, yīnwèi kěyǐ hé māma yìqǐ qù shìchǎng.',
    'Рядом с моим домом есть очень большой рынок, там много всего, и недорого. По субботам утром мама часто берёт меня с собой на рынок за покупками. На рынке продают фрукты, продают овощи, а ещё продают рыбу и мясо. Мне больше всего нравится ходить с мамой за фруктами, потому что фрукты сладкие и вкусные. Сегодня мы купили яблоки, бананы и арбуз. Мама ещё купила яйца, молоко и хлеб. На рынке очень много людей, очень оживлённо, все разговаривают, покупают вещи. Купив всё, мы сели на автобус и поехали домой. Когда мы добрались домой, я уже был(а) очень голоден(на), мама сразу же начала готовить нам еду. Мы всей семьёй вместе едим, разговариваем об интересных вещах, которые видели сегодня на рынке. Мне очень нравится суббота, потому что можно вместе с мамой пойти на рынок.',
    1
),
(
    'Мои друзья',
    '我有很多朋友,他们都很好。我最好的朋友叫小明,他住在我家旁边。我们从小就认识,一起上学,一起玩儿。小明很聪明,他的汉语说得比我好。他也很喜欢运动,每天下午都去打篮球。我不太会打篮球,但是我喜欢看他打球。我还有一个朋友叫小红,她是我的同学。小红很安静,她喜欢看书、画画儿。我们三个人常常在周末一起做作业,一起吃饭。有时候我们也去公园玩儿,骑自行车,或者去小明家看电视。我觉得有好朋友是一件很幸福的事情。',
    'Wǒ yǒu hěn duō péngyou, tāmen dōu hěn hǎo. Wǒ zuì hǎo de péngyou jiào Xiǎo Míng, tā zhù zài wǒ jiā pángbiān. Wǒmen cóngxiǎo jiù rènshi, yìqǐ shàngxué, yìqǐ wánr. Xiǎo Míng hěn cōngming, tā de Hànyǔ shuō de bǐ wǒ hǎo. Tā yě hěn xǐhuan yùndòng, měitiān xiàwǔ dōu qù dǎ lánqiú. Wǒ bú tài huì dǎ lánqiú, dànshì wǒ xǐhuan kàn tā dǎqiú. Wǒ hái yǒu yí gè péngyou jiào Xiǎo Hóng, tā shì wǒ de tóngxué. Xiǎo Hóng hěn ānjìng, tā xǐhuan kànshū, huàhuàr. Wǒmen sān gè rén chángcháng zài zhōumò yìqǐ zuò zuòyè, yìqǐ chīfàn. Yǒu shíhou wǒmen yě qù gōngyuán wánr, qí zìxíngchē, huòzhě qù Xiǎo Míng jiā kàn diànshì. Wǒ juéde yǒu hǎo péngyou shì yí jiàn hěn xìngfú de shìqing.',
    'У меня много друзей, и все они очень хорошие. Моего лучшего друга зовут Сяо Мин, он живёт рядом с моим домом. Мы знакомы с детства, вместе ходим в школу, вместе играем. Сяо Мин очень умный, он говорит по-китайски лучше меня. Он также очень любит спорт, каждый день после обеда ходит играть в баскетбол. Я не очень умею играть в баскетбол, но мне нравится смотреть, как он играет. У меня есть ещё подруга по имени Сяо Хун, она моя одноклассница. Сяо Хун очень спокойная, она любит читать книги, рисовать. Мы втроём часто по выходным вместе делаем домашнее задание, вместе едим. Иногда мы ещё ходим в парк играть, катаемся на велосипеде, или идём к Сяо Мину домой смотреть телевизор. Я думаю, что иметь хороших друзей — это очень счастливая вещь.',
    1
),
(
    'Поездка к бабушке',
    '上个周末,我和爸爸妈妈一起去看奶奶。奶奶住在乡下,离我们家有两个小时的车程。虽然路上花了不少时间,但是一路上的风景非常美,路两边都是绿色的田地和高高的树。到了奶奶家,奶奶已经准备好了一大桌好吃的菜,有我最喜欢吃的红烧肉和炒青菜。奶奶看到我们,特别高兴,一直问我在学校学得怎么样,身体好不好。吃完饭以后,我陪奶奶在院子里散步,还帮她浇花、喂鸡。晚上,我们坐在院子里聊天,看星星,奶奶给我讲了很多她年轻时候的故事。第二天早上,我们要回城里了,奶奶给我们准备了很多自己种的蔬菜和水果,让我们带回家。坐在回家的车上,我一直在想,应该多找时间来看奶奶。',
    'Shàng gè zhōumò, wǒ hé bàba māma yìqǐ qù kàn nǎinai. Nǎinai zhù zài xiāngxià, lí wǒmen jiā yǒu liǎng gè xiǎoshí de chēchéng. Suīrán lùshang huāle bù shǎo shíjiān, dànshì yílù shàng de fēngjǐng fēicháng měi, lù liǎngbiān dōu shì lǜsè de tiándì hé gāogāo de shù. Dàole nǎinai jiā, nǎinai yǐjīng zhǔnbèi hǎole yí dà zhuō hǎochī de cài, yǒu wǒ zuì xǐhuan chī de hóngshāoròu hé chǎo qīngcài. Nǎinai kàndào wǒmen, tèbié gāoxìng, yìzhí wèn wǒ zài xuéxiào xué de zěnmeyàng, shēntǐ hǎo bù hǎo. Chīwán fàn yǐhòu, wǒ péi nǎinai zài yuànzi lǐ sànbù, hái bāng tā jiāo huā, wèi jī. Wǎnshang, wǒmen zuò zài yuànzi lǐ liáotiān, kàn xīngxing, nǎinai gěi wǒ jiǎngle hěn duō tā niánqīng shíhou de gùshi. Dì''èr tiān zǎoshang, wǒmen yào huí chéng lǐ le, nǎinai gěi wǒmen zhǔnbèile hěn duō zìjǐ zhòng de shūcài hé shuǐguǒ, ràng wǒmen dài huí jiā. Zuò zài huí jiā de chē shàng, wǒ yìzhí zài xiǎng, yīnggāi duō zhǎo shíjiān lái kàn nǎinai.',
    'В прошлые выходные я вместе с папой и мамой поехал(а) навестить бабушку. Бабушка живёт в деревне, до нашего дома два часа езды. Хотя дорога заняла немало времени, пейзажи по пути были очень красивыми, по обеим сторонам дороги — зелёные поля и высокие деревья. Приехав к бабушке домой, мы увидели, что она уже приготовила целый стол вкусных блюд, в том числе моё любимое тушёное мясо и жареные овощи. Увидев нас, бабушка очень обрадовалась, всё время спрашивала, как у меня дела с учёбой в школе, здорова ли я. После еды я гулял(а) с бабушкой по двору, а ещё помогал(а) ей поливать цветы и кормить кур. Вечером мы сидели во дворе, разговаривали, смотрели на звёзды, бабушка рассказала мне много историй из своей молодости. На следующее утро нам нужно было возвращаться в город, бабушка приготовила нам много овощей и фруктов, которые сама вырастила, чтобы мы взяли их с собой домой. Сидя в машине по дороге домой, я всё думал(а), что нужно чаще находить время, чтобы навещать бабушку.',
    2
),
(
    'Мой любимый ресторан',
    '在我家附近有一家小饭馆,虽然地方不大,但是那里的菜做得特别好吃,所以我常常和朋友一起去那儿吃饭。这家饭馆是一对老夫妻开的,他们已经在这里做了二十多年的生意了。老板做的红烧鱼是我最喜欢的一道菜,又香又嫩,一点儿也不腥。老板娘的性格很好,每次我们去,她都会热情地跟我们打招呼,有时候还会送我们一些小菜。因为这家饭馆的菜好吃,价格也不贵,所以生意一直很好,吃饭的时候常常需要等座位。上个星期,我带外国朋友去了这家饭馆,他吃了以后说这是他在中国吃过的最好吃的菜。听到这句话,我心里特别高兴,好像自己开的饭馆一样。以后有机会,我还想带更多朋友去尝尝这家饭馆的菜。',
    'Zài wǒ jiā fùjìn yǒu yì jiā xiǎo fànguǎn, suīrán dìfang bú dà, dànshì nàlǐ de cài zuò de tèbié hǎochī, suǒyǐ wǒ chángcháng hé péngyou yìqǐ qù nàr chīfàn. Zhè jiā fànguǎn shì yí duì lǎo fūqī kāi de, tāmen yǐjīng zài zhèlǐ zuòle èrshí duō nián de shēngyi le. Lǎobǎn zuò de hóngshāoyú shì wǒ zuì xǐhuan de yí dào cài, yòu xiāng yòu nèn, yìdiǎnr yě bù xīng. Lǎobǎnniáng de xìnggé hěn hǎo, měicì wǒmen qù, tā dōu huì rèqíng de gēn wǒmen dǎzhāohu, yǒu shíhou hái huì sòng wǒmen yìxiē xiǎocài. Yīnwèi zhè jiā fànguǎn de cài hǎochī, jiàgé yě bú guì, suǒyǐ shēngyi yìzhí hěn hǎo, chīfàn de shíhou chángcháng xūyào děng zuòwèi. Shàng gè xīngqī, wǒ dài wàiguó péngyou qùle zhè jiā fànguǎn, tā chīle yǐhòu shuō zhè shì tā zài Zhōngguó chīguò de zuì hǎochī de cài. Tīngdào zhè jù huà, wǒ xīnlǐ tèbié gāoxìng, hǎoxiàng zìjǐ kāi de fànguǎn yíyàng. Yǐhòu yǒu jīhuì, wǒ hái xiǎng dài gèng duō péngyou qù chángchang zhè jiā fànguǎn de cài.',
    'Рядом с моим домом есть небольшой ресторанчик, хотя место небольшое, но еду там готовят особенно вкусно, поэтому я часто хожу туда с друзьями поесть. Этот ресторан держит пожилая супружеская пара, они уже больше двадцати лет ведут здесь бизнес. Тушёная рыба, которую готовит хозяин, — моё самое любимое блюдо, ароматная и нежная, совсем без запаха тины. У хозяйки очень хороший характер, каждый раз, когда мы приходим, она тепло с нами здоровается, а иногда ещё угощает нас небольшими закусками. Так как еда в этом ресторане вкусная, а цены недорогие, дела там всегда идут хорошо, во время еды часто приходится ждать свободный столик. На прошлой неделе я привёл(привела) в этот ресторан иностранного друга, попробовав еду, он сказал, что это самое вкусное блюдо, которое он ел в Китае. Услышав эти слова, я был(а) очень рад(а), как будто это был мой собственный ресторан. Если будет возможность, я хочу привести туда ещё больше друзей попробовать блюда этого ресторана.',
    2
),
(
    'История одного письма',
    '去年冬天,我在整理旧书的时候,发现了一封没有寄出去的信。那是我上大学的时候写给一位老朋友的信,因为搬家的原因,一直忘记寄出去,一放就是好几年。信里写的都是我们一起上学时候的回忆:一起在图书馆复习功课,一起在食堂排队买饭,还有一起在校园里散步聊天到很晚的日子。看着自己当年写的字,我忽然觉得时间过得真快,那些看似普通的日子,现在回想起来却那么珍贵。我马上给那位朋友打了电话,虽然我们已经很多年没有联系了,但是他一听到我的声音,就立刻认出了我。我们聊了很久,聊起了这封迟到的信,也聊起了各自这些年的生活。挂了电话以后,我决定还是把这封信寄给他,虽然晚了很多年,但是我相信,这份友谊和这份心意,永远都不会过时。',
    'Qùnián dōngtiān, wǒ zài zhěnglǐ jiù shū de shíhou, fāxiànle yì fēng méiyǒu jì chūqù de xìn. Nà shì wǒ shàng dàxué de shíhou xiě gěi yí wèi lǎo péngyou de xìn, yīnwèi bānjiā de yuányīn, yìzhí wàngjì jì chūqù, yí fàng jiùshì hǎo jǐ nián. Xìn lǐ xiě de dōu shì wǒmen yìqǐ shàngxué shíhou de huíyì: yìqǐ zài túshūguǎn fùxí gōngkè, yìqǐ zài shítáng páiduì mǎi fàn, hái yǒu yìqǐ zài xiàoyuán lǐ sànbù liáotiān dào hěn wǎn de rìzi. Kànzhe zìjǐ dāngnián xiě de zì, wǒ hūrán juéde shíjiān guò de zhēn kuài, nàxiē kànsì pǔtōng de rìzi, xiànzài huíxiǎng qǐlái què nàme zhēnguì. Wǒ mǎshàng gěi nà wèi péngyou dǎle diànhuà, suīrán wǒmen yǐjīng hěn duō nián méiyǒu liánxì le, dànshì tā yì tīngdào wǒ de shēngyīn, jiù lìkè rènchūle wǒ. Wǒmen liáole hěn jiǔ, liáoqǐle zhè fēng chídào de xìn, yě liáoqǐle gèzì zhèxiē nián de shēnghuó. Guàle diànhuà yǐhòu, wǒ juédìng háishi bǎ zhè fēng xìn jì gěi tā, suīrán wǎnle hěn duō nián, dànshì wǒ xiāngxìn, zhè fèn yǒuyì hé zhè fèn xīnyì, yǒngyuǎn dōu bú huì guòshí.',
    'Прошлой зимой, разбирая старые книги, я обнаружил(а) неотправленное письмо. Это было письмо, написанное ещё в университете одному старому другу, но из-за переезда я всё время забывал(а) его отправить, и так пролежало оно несколько лет. В письме были описаны наши общие воспоминания об учёбе: как мы вместе готовились к занятиям в библиотеке, вместе стояли в очереди за едой в столовой, а ещё дни, когда мы гуляли по кампусу и разговаривали допоздна. Глядя на собственный почерк тех лет, я вдруг почувствовал(а), как быстро летит время — те дни, казавшиеся тогда обычными, сейчас, вспоминая их, кажутся такими драгоценными. Я сразу же позвонил(а) тому другу, и хотя мы не общались уже много лет, он, услышав мой голос, сразу же меня узнал. Мы долго разговаривали, вспоминали это запоздавшее письмо, а также говорили о том, как сложилась жизнь каждого из нас за эти годы. Повесив трубку, я всё же решил(а) отправить ему это письмо — хотя и с опозданием на много лет, но я верю, что эта дружба и это чувство никогда не устареют.',
    3
),
(
    'Первый день на работе',
    '今天是我在新公司上班的第一天,昨天晚上我几乎没睡好,一直在想第一天应该穿什么衣服,应该怎么跟同事打招呼。早上七点,我就起床了,虽然公司九点才上班,但是我还是提前一个小时出门,怕路上堵车迟到。到了公司门口,我的心跳得很快,深呼吸了几次才走进去。前台的姐姐很热情,带我认识了办公室的环境,还给我介绍了几位同事。我的经理是一位四十多岁的男士,他看起来很严肃,但是说话的时候却很温和,他给我讲了公司的规定,还给了我一些工作上的建议。中午吃饭的时候,几个同事主动过来跟我聊天,问我以前在哪里工作,为什么选择这家公司。他们的热情让我紧张的心情放松了不少。下午,经理给了我第一个任务,虽然不太难,但是我还是花了很长时间,反复检查了好几遍才交给他。下班的时候,我觉得虽然很累,但是很充实,我相信只要努力,我一定可以在这里做得很好。',
    'Jīntiān shì wǒ zài xīn gōngsī shàngbān de dì-yī tiān, zuótiān wǎnshang wǒ jīhū méi shuì hǎo, yìzhí zài xiǎng dì-yī tiān yīnggāi chuān shénme yīfu, yīnggāi zěnme gēn tóngshì dǎzhāohu. Zǎoshang qī diǎn, wǒ jiù qǐchuáng le, suīrán gōngsī jiǔ diǎn cái shàngbān, dànshì wǒ háishi tíqián yí gè xiǎoshí chūmén, pà lùshang dǔchē chídào. Dàole gōngsī ménkǒu, wǒ de xīn tiào de hěn kuài, shēnhūxīle jǐ cì cái zǒu jìnqù. Qiántái de jiějie hěn rèqíng, dài wǒ rènshile bàngōngshì de huánjìng, hái gěi wǒ jièshàole jǐ wèi tóngshì. Wǒ de jīnglǐ shì yí wèi sìshí duō suì de nánshì, tā kàn qǐlái hěn yánsù, dànshì shuōhuà de shíhou què hěn wēnhé, tā gěi wǒ jiǎngle gōngsī de guīdìng, hái gěile wǒ yìxiē gōngzuò shàng de jiànyì. Zhōngwǔ chīfàn de shíhou, jǐ gè tóngshì zhǔdòng guòlái gēn wǒ liáotiān, wèn wǒ yǐqián zài nǎlǐ gōngzuò, wèishénme xuǎnzé zhè jiā gōngsī. Tāmen de rèqíng ràng wǒ jǐnzhāng de xīnqíng fàngsōngle bù shǎo. Xiàwǔ, jīnglǐ gěile wǒ dì-yī gè rènwu, suīrán bú tài nán, dànshì wǒ háishi huāle hěn cháng shíjiān, fǎnfù jiǎnchále hǎo jǐ biàn cái jiāo gěi tā. Xiàbān de shíhou, wǒ juéde suīrán hěn lèi, dànshì hěn chōngshí, wǒ xiāngxìn zhǐyào nǔlì, wǒ yídìng kěyǐ zài zhèlǐ zuò de hěn hǎo.',
    'Сегодня мой первый день на новой работе, вчера вечером я почти не выспался(лась), всё думал(а) о том, что надеть в первый день, как здороваться с коллегами. Утром в семь часов я уже встал(а), хотя работа в компании начинается только в девять, но я всё равно вышел(вышла) из дома на час раньше, боясь опоздать из-за пробок. Дойдя до входа в компанию, я почувствовал(а), как сильно бьётся сердце, и, сделав несколько глубоких вдохов, вошёл(вошла) внутрь. Девушка на ресепшене оказалась очень приветливой, она показала мне офис и познакомила с несколькими коллегами. Мой руководитель — мужчина лет сорока, на вид он выглядел очень строгим, но когда говорил, был очень мягким, он рассказал мне о правилах компании и дал несколько советов по работе. Во время обеда несколько коллег сами подошли поговорить со мной, спрашивали, где я раньше работал(а), почему выбрал(а) эту компанию. Их дружелюбие значительно уменьшило моё напряжение. Днём руководитель дал мне первое задание, хотя оно было не очень сложным, я всё равно потратил(а) много времени, несколько раз перепроверил(а), прежде чем сдать. Когда рабочий день закончился, я почувствовал(а), что хотя и устал(а), но чувствую себя наполненным(ой) смыслом, и верю, что если буду стараться, обязательно смогу хорошо здесь работать.',
    3
),
(
    'Как изменились путешествия за последние годы',
    '过去,人们出门旅行往往需要提前很长时间做准备:查地图、订车票、订酒店,每一个环节都可能花费大量的时间和精力。而且,由于信息获取的渠道有限,很多人只能依靠旅行社安排的固定路线,很难根据自己的兴趣自由安排行程。然而,随着互联网技术的飞速发展,人们的旅行方式已经发生了翻天覆地的变化。如今,只需要一部手机,就可以在几分钟之内完成机票和酒店的预订,还能实时查看目的地的天气、交通和景点信息。社交媒体和短视频平台的兴起,也让越来越多的人开始追求个性化、深度化的旅行体验,而不再满足于走马观花式的观光。与此同时,自由行、自驾游等旅行方式也变得越来越受欢迎,人们更愿意按照自己的节奏,慢慢地去感受一个地方的文化和生活。当然,便利的科技也带来了一些新的问题,比如某些热门景点因为游客过多而不堪重负,一些原本安静的小镇也因为过度商业化而失去了原有的特色。如何在享受科技带来的便利的同时,保护好旅行目的地的自然环境和人文风貌,是值得每一位旅行者深思的问题。',
    'Guòqù, rénmen chūmén lǚxíng wǎngwǎng xūyào tíqián hěn cháng shíjiān zuò zhǔnbèi: chá dìtú, dìng chēpiào, dìng jiǔdiàn, měi yí gè huánjié dōu kěnéng huāfèi dàliàng de shíjiān hé jīnglì. Érqiě, yóuyú xìnxī huòqǔ de qúdào yǒuxiàn, hěn duō rén zhǐ néng yīkào lǚxíngshè ānpái de gùdìng lùxiàn, hěn nán gēnjù zìjǐ de xìngqù zìyóu ānpái xíngchéng. Rán''ér, suízhe hùliánwǎng jìshù de fēisù fāzhǎn, rénmen de lǚxíng fāngshì yǐjīng fāshēngle fāntiānfùdì de biànhuà. Rújīn, zhǐ xūyào yí bù shǒujī, jiù kěyǐ zài jǐ fēnzhōng zhī nèi wánchéng jīpiào hé jiǔdiàn de yùdìng, hái néng shíshí chákàn mùdìdì de tiānqì, jiāotōng hé jǐngdiǎn xìnxī. Shèjiāo méitǐ hé duǎn shìpín píngtái de xīngqǐ, yě ràng yuè lái yuè duō de rén kāishǐ zhuīqiú gèxìnghuà, shēndùhuà de lǚxíng tǐyàn, ér bú zài mǎnzú yú zǒumǎguānhuā shì de guānguāng. Yǔcǐtóngshí, zìyóuxíng, zìjiàyóu děng lǚxíng fāngshì yě biàn de yuè lái yuè shòu huānyíng, rénmen gèng yuànyì ànzhào zìjǐ de jiézòu, mànmàn de qù gǎnshòu yí gè dìfang de wénhuà hé shēnghuó. Dāngrán, biànlì de kējì yě dàiláile yìxiē xīn de wèntí, bǐrú mǒuxiē rèmén jǐngdiǎn yīnwèi yóukè guò duō ér bùkān zhòngfù, yìxiē yuánběn ānjìng de xiǎozhèn yě yīnwèi guòdù shāngyèhuà ér shīqùle yuányǒu de tèsè. Rúhé zài xiǎngshòu kējì dàilái de biànlì de tóngshí, bǎohù hǎo lǚxíng mùdìdì de zìrán huánjìng hé rénwén fēngmào, shì zhíde měi yí wèi lǚxíngzhě shēnsī de wèntí.',
    'Раньше, отправляясь путешествовать, людям часто приходилось заранее долго готовиться: изучать карты, бронировать билеты, бронировать гостиницы, — на каждый этап могло уходить много времени и сил. Более того, из-за ограниченности каналов получения информации многие могли полагаться только на фиксированные маршруты, предложенные турагентствами, и с трудом составляли поездку по собственным интересам. Однако с стремительным развитием интернет-технологий способы путешествий людей претерпели колоссальные изменения. Сегодня достаточно одного телефона, чтобы за несколько минут забронировать авиабилеты и гостиницу, а также в реальном времени узнавать о погоде, транспорте и достопримечательностях места назначения. Расцвет социальных сетей и платформ коротких видео также заставил всё больше людей стремиться к персонализированному, глубокому опыту путешествий, вместо того чтобы довольствоваться беглым осмотром достопримечательностей. В то же время самостоятельные путешествия и автопутешествия становятся всё более популярными, люди предпочитают следовать собственному ритму, неспешно ощущая культуру и жизнь того или иного места. Конечно, удобные технологии принесли и новые проблемы: например, некоторые популярные достопримечательности не выдерживают наплыва туристов, а некоторые изначально тихие городки утратили свою самобытность из-за чрезмерной коммерциализации. Вопрос о том, как, пользуясь удобствами технологий, одновременно защищать природную среду и культурный облик мест путешествий, заслуживает серьёзного размышления каждого путешественника.',
    4
),
(
    'Значение чтения в цифровую эпоху',
    '在智能手机和平板电脑普及之前,阅读纸质书籍几乎是获取知识的唯一途径。人们会花大量的时间坐在图书馆或者书房里,一页一页地翻阅书本,慢慢地思考书中的内容。然而,进入数字时代以后,电子书、有声书以及各种阅读类应用软件的出现,极大地改变了人们的阅读习惯。如今,只需要打开手机,就可以随时随地阅读成千上万本电子书,这无疑给阅读带来了极大的便利。不过,便利的同时也带来了新的挑战。研究显示,由于手机上充斥着各种信息和娱乐内容,很多人在阅读电子书的时候容易分心,难以像阅读纸质书那样保持长时间的专注。此外,碎片化的阅读方式,也使得人们越来越习惯于快速浏览,而不愿意花时间去深入思考一本书真正想要表达的内容。面对这样的现象,不少教育专家呼吁,家长和学校应该从小培养孩子深度阅读的习惯,让他们既能享受数字阅读带来的便利,又不失去静下心来品味一本好书的能力。毕竟,无论科技如何发展,阅读所带来的思考和成长,始终是任何工具都无法替代的。',
    'Zài zhìnéng shǒujī hé píngbǎn diànnǎo pǔjí zhīqián, yuèdú zhǐzhì shūjí jīhū shì huòqǔ zhīshi de wéiyī tújìng. Rénmen huì huā dàliàng de shíjiān zuò zài túshūguǎn huòzhě shūfáng lǐ, yí yè yí yè de fānyuè shūběn, mànmàn de sīkǎo shū zhōng de nèiróng. Rán''ér, jìnrù shùzì shídài yǐhòu, diànzǐshū, yǒushēngshū yǐjí gèzhǒng yuèdúlèi yìngyòng ruǎnjiàn de chūxiàn, jídà de gǎibiànle rénmen de yuèdú xíguàn. Rújīn, zhǐ xūyào dǎkāi shǒujī, jiù kěyǐ suíshí suídì yuèdú chéngqiānshàngwàn běn diànzǐshū, zhè wúyí gěi yuèdú dàiláile jídà de biànlì. Búguò, biànlì de tóngshí yě dàiláile xīn de tiǎozhàn. Yánjiū xiǎnshì, yóuyú shǒujī shàng chōngchìzhe gèzhǒng xìnxī hé yúlè nèiróng, hěn duō rén zài yuèdú diànzǐshū de shíhou róngyì fēnxīn, nányǐ xiàng yuèdú zhǐzhìshū nàyàng bǎochí cháng shíjiān de zhuānzhù. Cǐwài, suìpiànhuà de yuèdú fāngshì, yě shǐde rénmen yuè lái yuè xíguàn yú kuàisù liúlǎn, ér bú yuànyì huā shíjiān qù shēnrù sīkǎo yì běn shū zhēnzhèng xiǎng yào biǎodá de nèiróng. Miànduì zhèyàng de xiànxiàng, bù shǎo jiàoyù zhuānjiā hūyù, jiāzhǎng hé xuéxiào yīnggāi cóngxiǎo péiyǎng háizi shēndù yuèdú de xíguàn, ràng tāmen jì néng xiǎngshòu shùzì yuèdú dàilái de biànlì, yòu bù shīqù jìngxiàxīn lái pǐnwèi yì běn hǎo shū de nénglì. Bìjìng, wúlùn kējì rúhé fāzhǎn, yuèdú suǒ dàilái de sīkǎo hé chéngzhǎng, shǐzhōng shì rènhé gōngjù dōu wúfǎ tìdài de.',
    'До того как смартфоны и планшеты стали повсеместными, чтение бумажных книг было практически единственным способом получения знаний. Люди тратили много времени, сидя в библиотеке или кабинете, листая книгу страницу за страницей, медленно обдумывая её содержание. Однако с наступлением цифровой эпохи появление электронных книг, аудиокниг и различных приложений для чтения значительно изменило читательские привычки людей. Сегодня достаточно открыть телефон, чтобы в любое время и в любом месте читать тысячи электронных книг, что, безусловно, принесло чтению огромное удобство. Однако вместе с удобством пришли и новые вызовы. Исследования показывают, что поскольку телефон переполнен всевозможной информацией и развлекательным контентом, многим людям трудно сосредоточиться при чтении электронных книг, сложно сохранять длительную концентрацию, как при чтении бумажной книги. Кроме того, фрагментарный способ чтения приводит к тому, что люди всё больше привыкают к быстрому просмотру и не хотят тратить время на глубокое осмысление того, что на самом деле хочет выразить книга. Столкнувшись с таким явлением, немало экспертов в области образования призывают родителей и школы с детства прививать детям привычку глубокого чтения, чтобы они могли одновременно наслаждаться удобством цифрового чтения и не терять способность спокойно вникать в хорошую книгу. Ведь как бы ни развивались технологии, размышления и рост, которые даёт чтение, всегда останутся тем, что не может заменить ни один инструмент.',
    4
),
(
    'Кризис доверия в интернете',
    '互联网的普及,原本应该让信息的传播变得更加透明、便捷,然而近年来,网络上虚假信息、恶意炒作以及"标题党"现象层出不穷,使得公众对网络信息的信任度不断下降,一种被称为"信任危机"的社会现象正在悄然蔓延。造成这一现象的原因是多方面的。首先,部分自媒体为了追求流量和点击率,不惜编造耸人听闻的标题和内容,甚至歪曲事实真相,严重误导了公众的判断。其次,一些别有用心的人利用网络的匿名性,散布谣言、制造对立,借机谋取不正当利益。此外,普通网民自身的媒介素养参差不齐,也是导致虚假信息广泛传播的重要因素——很多人在没有核实信息真伪的情况下,便盲目转发、评论,无形中成为了谣言传播链条中的一环。要想真正化解这场信任危机,仅仅依靠平台的监管远远不够,还需要政府完善相关法律法规,加大对造谣传谣行为的惩处力度;媒体机构应当坚守新闻的真实性原则,不为流量而牺牲职业操守;而作为普通网民,我们每个人也应该主动提高自己的媒介素养,学会独立思考、理性判断,不轻易被表面的信息所左右。唯有多方共同努力,才能重建一个健康、可信的网络环境。',
    'Hùliánwǎng de pǔjí, yuánběn yīnggāi ràng xìnxī de chuánbò biàn de gèngjiā tòumíng, biànjié, rán''ér jìnnián lái, wǎngluò shàng xūjiǎ xìnxī, èyì chǎozuò yǐjí "biāotídǎng" xiànxiàng céngchūbùqióng, shǐde gōngzhòng duì wǎngluò xìnxī de xìnrèndù búduàn xiàjiàng, yì zhǒng bèi chēngwéi "xìnrèn wēijī" de shèhuì xiànxiàng zhèngzài qiāorán mànyán. Zàochéng zhè yí xiànxiàng de yuányīn shì duō fāngmiàn de. Shǒuxiān, bùfen zìméitǐ wèile zhuīqiú liúliàng hé diǎnjīlǜ, bùxī biānzào sǒngréntīngwén de biāotí hé nèiróng, shènzhì wāiqū shìshí zhēnxiàng, yánzhòng wùdǎole gōngzhòng de pànduàn. Qící, yìxiē biéyǒuyòngxīn de rén lìyòng wǎngluò de nìmíngxìng, sànbù yáoyán, zhìzào duìlì, jièjī móuqǔ búzhèngdàng lìyì. Cǐwài, pǔtōng wǎngmín zìshēn de méijiè sùyǎng cēncībùqí, yě shì dǎozhì xūjiǎ xìnxī guǎngfàn chuánbò de zhòngyào yīnsù — hěn duō rén zài méiyǒu héshí xìnxī zhēnwěi de qíngkuàng xià, biàn mángmù zhuǎnfā, pínglùn, wúxíng zhōng chéngwéile yáoyán chuánbò liàntiáo zhōng de yì huán. Yào xiǎng zhēnzhèng huàjiě zhè chǎng xìnrèn wēijī, jǐnjǐn yīkào píngtái de jiānguǎn yuǎnyuǎn bú gòu, hái xūyào zhèngfǔ wánshàn xiāngguān fǎlǜ fǎguī, jiādà duì zàoyáo chuányáo xíngwéi de chéngchǔ lìdù; méitǐ jīgòu yīngdāng jiānshǒu xīnwén de zhēnshíxìng yuánzé, bù wèi liúliàng ér xīshēng zhíyè cāoshǒu; ér zuòwéi pǔtōng wǎngmín, wǒmen měi gè rén yě yīnggāi zhǔdòng tígāo zìjǐ de méijiè sùyǎng, xuéhuì dúlì sīkǎo, lǐxìng pànduàn, bù qīngyì bèi biǎomiàn de xìnxī suǒ zuǒyòu. Wéiyǒu duō fāng gòngtóng nǔlì, cáinéng chóngjiàn yí gè jiànkāng, kěxìn de wǎngluò huánjìng.',
    'Распространение интернета изначально должно было сделать передачу информации более прозрачной и удобной, однако в последние годы в сети непрерывно появляются ложная информация, злонамеренный хайп и явление «кликбейтных заголовков», что приводит к постоянному снижению доверия общественности к сетевой информации — незаметно распространяется социальное явление, называемое «кризисом доверия». Причины этого явления многообразны. Во-первых, некоторые блогеры ради трафика и кликов не гнушаются придумывать сенсационные заголовки и содержание, даже искажая истинные факты, что серьёзно вводит в заблуждение суждения общественности. Во-вторых, некоторые люди с недобрыми намерениями пользуются анонимностью сети, распространяют слухи, создают противостояние, извлекая из этого неправомерную выгоду. Кроме того, неравномерный уровень медиаграмотности обычных пользователей сети также является важным фактором широкого распространения ложной информации — многие, не проверив достоверность информации, слепо репостят и комментируют, незаметно становясь звеном в цепи распространения слухов. Чтобы по-настоящему разрешить этот кризис доверия, одного лишь регулирования со стороны платформ далеко не достаточно — необходимо, чтобы правительство совершенствовало соответствующие законы и нормативные акты, усиливало наказание за распространение слухов; медиаорганизации должны придерживаться принципа достоверности новостей, не жертвуя профессиональной этикой ради трафика; а мы, обычные пользователи сети, каждый из нас также должен активно повышать собственную медиаграмотность, учиться самостоятельно мыслить, рационально оценивать, не поддаваясь легко поверхностной информации. Только совместными усилиями многих сторон можно восстановить здоровую, заслуживающую доверия сетевую среду.',
    5
),
(
    'Роль искусственного интеллекта в образовании',
    '近年来,人工智能技术在教育领域的应用越来越广泛,从智能批改作业、个性化学习推荐,到虚拟教师、智能答疑系统,人工智能正在悄然改变传统的教学模式。支持者认为,人工智能可以根据每个学生的学习进度和薄弱环节,提供量身定制的学习方案,大大提高学习效率,弥补传统"一刀切"式教学的不足。同时,人工智能还可以承担大量重复性的批改和统计工作,让教师有更多的时间和精力专注于课堂设计和与学生的互动。然而,也有不少教育专家对此表示担忧。他们认为,教育不仅仅是知识的传递,更是情感、价值观和人格的培养,而这些恰恰是冰冷的算法难以替代的。如果过度依赖人工智能,学生可能会习惯于被动接受系统给出的"标准答案",从而丧失独立思考和自主探索的能力。此外,人工智能技术的应用也带来了数据隐私、教育公平等方面的新问题——并非所有家庭都有条件让孩子接触到先进的教育科技,这可能进一步拉大教育资源本就存在的差距。因此,如何在发挥人工智能优势的同时,守住教育的人文内核,平衡技术与人的关系,将是未来教育改革需要持续探索的重要课题。',
    'Jìnnián lái, réngōng zhìnéng jìshù zài jiàoyù lǐngyù de yìngyòng yuè lái yuè guǎngfàn, cóng zhìnéng pīgǎi zuòyè, gèxìnghuà xuéxí tuījiàn, dào xūnǐ jiàoshī, zhìnéng dáyí xìtǒng, réngōng zhìnéng zhèngzài qiāorán gǎibiàn chuántǒng de jiàoxué móshì. Zhīchízhě rènwéi, réngōng zhìnéng kěyǐ gēnjù měi gè xuésheng de xuéxí jìndù hé bóruò huánjié, tígōng liàngshēndìngzhì de xuéxí fāng''àn, dàdà tígāo xuéxí xiàolǜ, míbǔ chuántǒng "yìdāoqiè" shì jiàoxué de bùzú. Tóngshí, réngōng zhìnéng hái kěyǐ chéngdān dàliàng chóngfùxìng de pīgǎi hé tǒngjì gōngzuò, ràng jiàoshī yǒu gèng duō de shíjiān hé jīnglì zhuānzhù yú kètáng shèjì hé yǔ xuésheng de hùdòng. Rán''ér, yě yǒu bù shǎo jiàoyù zhuānjiā duì cǐ biǎoshì dānyōu. Tāmen rènwéi, jiàoyù bùjǐnjǐn shì zhīshi de chuándì, gèng shì qínggǎn, jiàzhíguān hé réngé de péiyǎng, ér zhèxiē qiàqià shì bīnglěng de suànfǎ nányǐ tìdài de. Rúguǒ guòdù yīlài réngōng zhìnéng, xuésheng kěnéng huì xíguàn yú bèidòng jiēshòu xìtǒng gěichū de "biāozhǔn dá''àn", cóng''ér sàngshī dúlì sīkǎo hé zìzhǔ tànsuǒ de nénglì. Cǐwài, réngōng zhìnéng jìshù de yìngyòng yě dàiláile shùjù yǐnsī, jiàoyù gōngpíng děng fāngmiàn de xīn wèntí — bìngfēi suǒyǒu jiātíng dōu yǒu tiáojiàn ràng háizi jiēchù dào xiānjìn de jiàoyù kējì, zhè kěnéng jìnyíbù lādà jiàoyù zīyuán běn jiù cúnzài de chājù. Yīncǐ, rúhé zài fāhuī réngōng zhìnéng yōushì de tóngshí, shǒuzhù jiàoyù de rénwén nèihé, pínghéng jìshù yǔ rén de guānxi, jiāng shì wèilái jiàoyù gǎigé xūyào chíxù tànsuǒ de zhòngyào kètí.',
    'В последние годы применение технологий искусственного интеллекта в сфере образования становится всё более широким — от интеллектуальной проверки домашних заданий, персонализированных рекомендаций по обучению до виртуальных преподавателей и систем интеллектуальных ответов на вопросы — искусственный интеллект незаметно меняет традиционную модель преподавания. Сторонники считают, что искусственный интеллект может, исходя из темпа обучения и слабых мест каждого ученика, предоставлять индивидуально подобранные учебные планы, значительно повышая эффективность обучения и восполняя недостатки традиционного «шаблонного» преподавания. Одновременно искусственный интеллект может взять на себя большой объём повторяющейся работы по проверке заданий и статистике, позволяя учителям больше времени и сил уделять разработке уроков и взаимодействию с учениками. Однако немало экспертов в сфере образования выражают по этому поводу обеспокоенность. Они считают, что образование — это не только передача знаний, но и воспитание эмоций, ценностей и личности, а именно это трудно заменить холодным алгоритмом. Если чрезмерно полагаться на искусственный интеллект, ученики могут привыкнуть пассивно принимать «стандартные ответы», выдаваемые системой, тем самым теряя способность самостоятельно мыслить и исследовать. Кроме того, применение технологий искусственного интеллекта также приносит новые проблемы в области конфиденциальности данных и справедливости образования — не у всех семей есть условия, чтобы дать детям доступ к передовым образовательным технологиям, что может ещё больше увеличить и без того существующий разрыв в образовательных ресурсах. Поэтому вопрос о том, как, используя преимущества искусственного интеллекта, сохранить гуманитарное ядро образования и сбалансировать отношения между технологией и человеком, станет важной темой, которую предстоит постоянно исследовать в ходе будущих реформ образования.',
    5
),
(
    'Диалектика перемен и постоянства',
    '中国古代哲学中有一个重要的概念,叫"变"与"不变"的辩证关系。《易经》中讲"穷则变,变则通,通则久",意思是说,任何事物发展到极致,都必须寻求变化,只有变化才能使事物继续发展,长久存在。然而,与此同时,古人也强调"以不变应万变"的智慧,认为在纷繁复杂、瞬息万变的外部世界中,人应当持守内心的原则和道德底线,不能因为外界的变化而随波逐流,失去自我。表面上看,"求变"与"守常"似乎是相互矛盾的两种态度,但实际上,二者恰恰是相辅相成、缺一不可的。真正懂得变化之道的人,往往是那些内心有着坚定信念和价值观的人——正因为他们清楚自己"不变"的是什么,才能够在具体的方式方法上灵活地"求变",而不至于迷失方向。反之,如果一个人内心没有任何坚守,即便表面上不断地追求变化和创新,最终也很可能沦为随波逐流、毫无原则的墙头草。在当今这个技术飞速迭代、社会观念不断更新的时代,重新审视"变"与"不变"的辩证关系,对于个人如何在纷繁复杂的世界中安身立命,依然具有十分重要的现实意义。',
    'Zhōngguó gǔdài zhéxué zhōng yǒu yí gè zhòngyào de gàiniàn, jiào "biàn" yǔ "bú biàn" de biànzhèng guānxi. "Yìjīng" zhōng jiǎng "qióng zé biàn, biàn zé tōng, tōng zé jiǔ", yìsi shì shuō, rènhé shìwù fāzhǎn dào jízhì, dōu bìxū xúnqiú biànhuà, zhǐyǒu biànhuà cáinéng shǐ shìwù jìxù fāzhǎn, chángjiǔ cúnzài. Rán''ér, yǔ cǐ tóngshí, gǔrén yě qiángdiào "yǐ bú biàn yìng wàn biàn" de zhìhuì, rènwéi zài fēnfán fùzá, shùnxī wànbiàn de wàibù shìjiè zhōng, rén yīngdāng chíshǒu nèixīn de yuánzé hé dàodé dǐxiàn, bù néng yīnwèi wàijiè de biànhuà ér suíbōzhúliú, shīqù zìwǒ. Biǎomiàn shàng kàn, "qiú biàn" yǔ "shǒu cháng" sìhū shì xiānghù máodùn de liǎng zhǒng tàidù, dàn shíjì shàng, èrzhě qiàqià shì xiāngfǔxiāngchéng, quē yī bù kě de. Zhēnzhèng dǒngde biànhuà zhī dào de rén, wǎngwǎng shì nàxiē nèixīn yǒuzhe jiāndìng xìnniàn hé jiàzhíguān de rén — zhèng yīnwèi tāmen qīngchu zìjǐ "bú biàn" de shì shénme, cái nénggòu zài jùtǐ de fāngshì fāngfǎ shàng línghuó de "qiú biàn", ér bú zhìyú míshī fāngxiàng. Fǎnzhī, rúguǒ yí gè rén nèixīn méiyǒu rènhé jiānshǒu, jíbiàn biǎomiàn shàng búduàn de zhuīqiú biànhuà hé chuàngxīn, zuìzhōng yě hěn kěnéng lúnwéi suíbōzhúliú, háowú yuánzé de qiángtóucǎo. Zài dāngjīn zhè ge jìshù fēisù diédài, shèhuì guānniàn búduàn gēngxīn de shídài, chóngxīn shěnshì "biàn" yǔ "bú biàn" de biànzhèng guānxi, duìyú gèrén rúhé zài fēnfán fùzá de shìjiè zhōng ānshēnlìmìng, yīrán jùyǒu shífēn zhòngyào de xiànshí yìyì.',
    'В древнекитайской философии есть важное понятие — диалектические отношения между «переменами» и «постоянством». В «Ицзин» («Книге перемен») говорится: «когда доходит до предела — меняется, когда меняется — становится проходимым, когда проходимо — длится долго», что означает: любая вещь, достигнув предела своего развития, обязательно должна искать перемен, и только перемены позволяют вещи продолжать развиваться и существовать долго. Однако одновременно с этим древние также подчёркивали мудрость «встречать все перемены неизменностью», полагая, что в запутанном, сложном и стремительно меняющемся внешнем мире человек должен твёрдо держаться внутренних принципов и нравственных устоев, не должен из-за внешних перемен плыть по течению и терять себя. На первый взгляд «стремление к переменам» и «сохранение постоянства» кажутся двумя противоречащими друг другу позициями, но на самом деле они как раз взаимно дополняют друг друга и неотделимы одна от другой. Люди, по-настоящему понимающие путь перемен, — это чаще всего те, у кого в душе есть твёрдые убеждения и ценности: именно потому, что они ясно понимают, что в них «неизменно», они и способны гибко «искать перемен» в конкретных способах и методах, не теряя при этом направления. И наоборот, если у человека в душе нет никакой твёрдой опоры, то даже если внешне он постоянно стремится к переменам и инновациям, в конце концов он вполне может превратиться в беспринципную «траву на вершине стены», плывущую по течению. В нынешнюю эпоху стремительной технологической смены поколений и постоянного обновления общественных представлений новое переосмысление диалектических отношений между «переменами» и «постоянством» по-прежнему имеет весьма важное практическое значение для того, как человек может обрести опору в сложном и запутанном мире.',
    6
),
(
    'Индивидуализм и коллективизм в китайской культуре',
    '在探讨中西方文化差异的时候,人们常常提到一个核心的对比维度,即"个人主义"与"集体主义"。西方文化,尤其是近代以来的欧美文化,普遍强调个人的独立性、自主性以及个人权利的至高无上,个体被视为社会的基本单位,个人的自我实现往往被赋予极高的价值。相比之下,以儒家思想为根基的中国传统文化,则更加强调集体的和谐与整体的利益,个人往往被置于家庭、宗族乃至国家等更大的集体框架之中来加以理解和定位。"修身、齐家、治国、平天下"这一儒家经典命题,清晰地体现了个人价值的实现是与家庭、社会、国家的兴衰紧密相连的这一观念。当然,随着全球化进程的深入以及中国社会自身的现代化转型,这种传统的集体主义观念也在悄然发生着变化。一方面,越来越多的年轻人开始追求个人梦想和自我价值的实现,不再完全依附于家庭或者集体的期望;另一方面,集体主义中所蕴含的团结互助、顾全大局的精神,在应对诸如公共卫生危机、自然灾害等重大挑战时,依然显示出不可替代的独特优势。由此可见,个人主义与集体主义并非简单的孰优孰劣的二元对立,而应该被理解为两种可以相互借鉴、相互补充的价值取向。在构建一个既尊重个体自由,又不失社会凝聚力的现代社会时,如何在这两种价值观之间找到恰当的平衡,是包括中国在内的许多国家都需要面对的共同课题。',
    'Zài tàntǎo Zhōng-Xīfāng wénhuà chāyì de shíhou, rénmen chángcháng tídào yí gè héxīn de duìbǐ wéidù, jí "gèrén zhǔyì" yǔ "jítǐ zhǔyì". Xīfāng wénhuà, yóuqí shì jìndài yǐlái de Ōuměi wénhuà, pǔbiàn qiángdiào gèrén de dúlìxìng, zìzhǔxìng yǐjí gèrén quánlì de zhìgāowúshàng, gètǐ bèi shìwéi shèhuì de jīběn dānwèi, gèrén de zìwǒ shíxiàn wǎngwǎng bèi fùyǔ jí gāo de jiàzhí. Xiāngbǐ zhī xià, yǐ Rújiā sīxiǎng wéi gēnjī de Zhōngguó chuántǒng wénhuà, zé gèngjiā qiángdiào jítǐ de héxié yǔ zhěngtǐ de lìyì, gèrén wǎngwǎng bèi zhìyú jiātíng, zōngzú nǎizhì guójiā děng gèng dà de jítǐ kuàngjià zhī zhōng lái jiāyǐ lǐjiě hé dìngwèi. "Xiūshēn, qíjiā, zhìguó, píngtiānxià" zhè yī Rújiā jīngdiǎn mìngtí, qīngchu de tǐxiànle gèrén jiàzhí de shíxiàn shì yǔ jiātíng, shèhuì, guójiā de xīngshuāi jǐnmì xiānglián de zhè yī guānniàn. Dāngrán, suízhe quánqiúhuà jìnchéng de shēnrù yǐjí Zhōngguó shèhuì zìshēn de xiàndàihuà zhuǎnxíng, zhè zhǒng chuántǒng de jítǐ zhǔyì guānniàn yě zài qiāorán fāshēngzhe biànhuà. Yì fāngmiàn, yuè lái yuè duō de niánqīngrén kāishǐ zhuīqiú gèrén mèngxiǎng hé zìwǒ jiàzhí de shíxiàn, bú zài wánquán yīfù yú jiātíng huòzhě jítǐ de qīwàng; lìng yì fāngmiàn, jítǐ zhǔyì zhōng suǒ yùnhán de tuánjié hùzhù, gùquán dàjú de jīngshén, zài yìngduì zhūrú gōnggòng wèishēng wēijī, zìrán zāihài děng zhòngdà tiǎozhàn shí, yīrán xiǎnshì chū bùkě tìdài de dútè yōushì. Yóucǐ kějiàn, gèrén zhǔyì yǔ jítǐ zhǔyì bìngfēi jiǎndān de shúyōu shúliè de èryuán duìlì, ér yīnggāi bèi lǐjiě wéi liǎng zhǒng kěyǐ xiānghù jièjiàn, xiānghù bǔchōng de jiàzhí qǔxiàng. Zài gòujiàn yí gè jì zūnzhòng gètǐ zìyóu, yòu bù shī shèhuì níngjùlì de xiàndài shèhuì shí, rúhé zài zhè liǎng zhǒng jiàzhíguān zhījiān zhǎodào qiàdàng de pínghéng, shì bāokuò Zhōngguó zài nèi de xǔduō guójiā dōu xūyào miànduì de gòngtóng kètí.',
    'При обсуждении культурных различий между Китаем и Западом люди часто упоминают одно ключевое измерение сравнения — «индивидуализм» и «коллективизм». Западная культура, особенно европейско-американская культура Нового времени, повсеместно подчёркивает независимость и самостоятельность личности, а также верховенство личных прав, индивид рассматривается как основная единица общества, самореализации личности часто придаётся исключительно высокая ценность. В отличие от этого, традиционная китайская культура, коренящаяся в конфуцианской мысли, больше подчёркивает гармонию коллектива и общие интересы, а личность часто рассматривается и определяется в рамках более широких коллективных структур — семьи, рода и даже государства. Классический конфуцианский тезис «совершенствуй себя, устрой семью, управляй государством, умиротвори Поднебесную» ясно отражает представление о том, что реализация личностной ценности тесно связана с процветанием и упадком семьи, общества и государства. Конечно, с углублением процесса глобализации и собственной модернизационной трансформацией китайского общества это традиционное представление о коллективизме также постепенно меняется. С одной стороны, всё больше молодых людей начинают стремиться к реализации личных мечтаний и собственной ценности, больше не полностью завися от ожиданий семьи или коллектива; с другой стороны, заложенный в коллективизме дух сплочённости, взаимопомощи и заботы об общих интересах по-прежнему демонстрирует незаменимое уникальное преимущество при столкновении с такими серьёзными вызовами, как кризисы общественного здравоохранения, стихийные бедствия. Из этого видно, что индивидуализм и коллективизм — это не простое бинарное противостояние «что лучше, что хуже», а должны пониматься как две ценностные ориентации, способные взаимно учиться друг у друга и взаимно дополнять друг друга. При построении современного общества, которое одновременно уважает свободу личности и сохраняет социальную сплочённость, вопрос о том, как найти подходящий баланс между этими двумя системами ценностей, — общая задача, с которой приходится сталкиваться многим странам, включая Китай.',
    6
);
